import re

def checkAdminPassword(password):
    if not password:
        return False
    if len(password) < 12 or len(password) > 20:
        return False
    if any(char.isspace() for char in password):
        return False
    if not re.search(r'[A-Z]', password):
        return False
    if not re.search(r'[a-z]', password):
        return False
    if not re.search(r'\d', password):
        return False
    if not re.search(r'[!@#$%^&*(),.?":{}|<>]', password):
        return False
    weak_passwords = {'password', '123456', '123456789', '12345', '1234567890', 'qwerty', 'abc123', 'password1', 'password2', '12345678', '123456789012'}
    if password in weak_passwords:
        return False
    return True

